This is a critical security concern. Missing function-level access control is one of the most common vulnerabilities, responsible for major breaches like the 2022 Optus incident where an unauthenticated API exposed 9.8 million customer records.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// Vulnerable: No authorization check on admin endpoint
app.get('/api/admin/users', async (req, res) => {
  try {
    const users = await db.query('SELECT * FROM users');
    res.json(users);
  } catch (error) {
    res.status(500).json({ error: 'Database error' });
  }
});

// Vulnerable: Only checks if user is logged in, not if they're admin
app.delete('/api/admin/users/:id', async (req, res) => {
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  // DANGER: Any authenticated user can delete any user!
  await db.query('DELETE FROM users WHERE id = ?', [req.params.id]);
  res.json({ message: 'User deleted' });
});

// Vulnerable: Relies on client-side role from request body
app.post('/api/admin/promote', async (req, res) => {
  const { targetUserId, newRole } = req.body;
  await db.query('UPDATE users SET role = ? WHERE id = ?', [newRole, targetUserId]);
  res.json({ message: 'Role updated' });
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker accesses admin endpoint without any authentication
curl https://api.example.com/api/admin/users

# Regular user promotes themselves to admin
curl -X POST https://api.example.com/api/admin/promote \
  -H "Content-Type: application/json" \
  -H "Cookie: session=regular_user_session" \
  -d '{"targetUserId": "attacker_id", "newRole": "admin"}'

# Any authenticated user deletes admin accounts
curl -X DELETE https://api.example.com/api/admin/users/1 \
  -H "Cookie: session=regular_user_session"
```

**Why This Is Dangerous**:
- First endpoint has NO authentication or authorization at all
- Second endpoint checks authentication but not authorization (role-based access)
- Third endpoint trusts client-supplied role data for privilege escalation
- Attackers can enumerate and access all user data
- Complete administrative takeover possible

**SECURE VERSION**:

```javascript
const express = require('express');
const app = express();

// Middleware: Verify JWT and attach user to request
const authenticateToken = async (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    // Fetch fresh user data from database (don't trust token claims alone)
    const user = await db.query('SELECT id, role FROM users WHERE id = ?', [decoded.userId]);
    if (!user) {
      return res.status(401).json({ error: 'User not found' });
    }
    req.user = user;
    next();
  } catch (error) {
    return res.status(403).json({ error: 'Invalid token' });
  }
};

// Middleware: Check if user has required role
const requireRole = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    if (!allowedRoles.includes(req.user.role)) {
      // Log unauthorized access attempt
      console.warn(`Unauthorized access attempt: User ${req.user.id} tried to access admin function`);
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    next();
  };
};

// Secure: Both authentication AND admin role required
app.get('/api/admin/users', 
  authenticateToken, 
  requireRole('admin', 'superadmin'),
  async (req, res) => {
    try {
      const users = await db.query('SELECT id, email, role, created_at FROM users');
      res.json(users);
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Secure: Admin check + prevent self-deletion
app.delete('/api/admin/users/:id',
  authenticateToken,
  requireRole('superadmin'),
  async (req, res) => {
    if (req.params.id === req.user.id) {
      return res.status(400).json({ error: 'Cannot delete your own account' });
    }

    await db.query('DELETE FROM users WHERE id = ?', [req.params.id]);
    res.json({ message: 'User deleted' });
  }
);

app.listen(3000);
```

**Key Security Controls**:
- **Authentication middleware**: Verifies JWT token and fetches fresh user data from database
- **Role-based authorization middleware**: Checks user role against allowed roles for each endpoint
- **Server-side role verification**: Never trusts client-provided role claims
- **Audit logging**: Records unauthorized access attempts for security monitoring

Excellent question! Resource-level access control (also called Attribute-Based Access Control or ABAC) is essential for multi-tenant applications and hierarchical organizations. This was a key failure in the 2023 Microsoft Power Platform vulnerability (CVE-2023-35311) where cross-tenant data access was possible.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();

// Security logging configuration
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Rate limiting for admin endpoints
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Permission definitions with resource-level rules
const PERMISSIONS = {
  'user:read': (user, resource) => {
    if (user.role === 'superadmin') return true;
    if (user.role === 'admin') return true;
    if (user.role === 'manager') return user.departmentId === resource.departmentId;
    return user.id === resource.id; // Users can read their own profile
  },
  'user:update': (user, resource) => {
    if (user.role === 'superadmin') return true;
    if (user.role === 'admin' && resource.role !== 'superadmin') return true;
    if (user.role === 'manager') {
      return user.departmentId === resource.departmentId && 
             !['admin', 'superadmin', 'manager'].includes(resource.role);
    }
    return user.id === resource.id; // Users can update their own profile
  },
  'user:delete': (user, resource) => {
    if (user.role === 'superadmin' && user.id !== resource.id) return true;
    if (user.role === 'admin') {
      return !['admin', 'superadmin'].includes(resource.role) && user.id !== resource.id;
    }
    return false; // Managers and regular users cannot delete
  },
  'department:manage': (user, resource) => {
    if (user.role === 'superadmin') return true;
    if (user.role === 'admin') return true;
    if (user.role === 'manager') return user.departmentId === resource.id;
    return false;
  }
};

// Enhanced authentication middleware
const authenticate = async (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    securityLogger.warn({
      event: 'auth_missing_token',
      ip: req.ip,
      path: req.path,
      timestamp: new Date().toISOString()
    });
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET, {
      algorithms: ['HS256'],
      issuer: process.env.JWT_ISSUER
    });

    // Always fetch fresh user data - never trust token claims for authorization
    const user = await db.query(
      'SELECT id, email, role, department_id as departmentId, is_active FROM users WHERE id = ?',
      [decoded.sub]
    );

    if (!user || !user.is_active) {
      securityLogger.warn({
        event: 'auth_invalid_user',
        userId: decoded.sub,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });
      return res.status(401).json({ error: 'Account inactive or not found' });
    }

    req.user = user;
    next();
  } catch (error) {
    securityLogger.warn({
      event: 'auth_token_invalid',
      error: error.message,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

// Resource-level authorization middleware factory
const authorize = (permission, resourceLoader) => {
  return async (req, res, next) => {
    try {
      // Load the resource being accessed
      const resource = await resourceLoader(req);

      if (!resource) {
        return res.status(404).json({ error: 'Resource not found' });
      }

      // Check permission against loaded resource
      const permissionCheck = PERMISSIONS[permission];
      if (!permissionCheck) {
        securityLogger.error({
          event: 'undefined_permission',
          permission,
          timestamp: new Date().toISOString()
        });
        return res.status(500).json({ error: 'Internal server error' });
      }

      const isAllowed = permissionCheck(req.user, resource);

      if (!isAllowed) {
        securityLogger.warn({
          event: 'authorization_denied',
          userId: req.user.id,
          userRole: req.user.role,
          permission,
          resourceId: resource.id,
          ip: req.ip,
          timestamp: new Date().toISOString()
        });
        return res.status(403).json({ error: 'Access denied' });
      }

      req.resource = resource;
      next();
    } catch (error) {
      securityLogger.error({
        event: 'authorization_error',
        error: error.message,
        userId: req.user?.id,
        timestamp: new Date().toISOString()
      });
      return res.status(500).json({ error: 'Internal server error' });
    }
  };
};

// Resource loaders
const loadUserResource = async (req) => {
  const userId = req.params.id;
  if (!userId || !/^[0-9a-f-]{36}$/i.test(userId)) {
    return null; // Invalid UUID format
  }
  return await db.query(
    'SELECT id, email, role, department_id as departmentId FROM users WHERE id = ?',
    [userId]
  );
};

const loadDepartmentResource = async (req) => {
  const deptId = req.params.departmentId;
  if (!deptId || !/^[0-9]+$/.test(deptId)) {
    return null;
  }
  return await db.query('SELECT id, name FROM departments WHERE id = ?', [deptId]);
};

// Protected routes with resource-level access control
app.get('/api/users/:id',
  adminLimiter,
  authenticate,
  authorize('user:read', loadUserResource),
  async (req, res) => {
    // req.resource is already loaded and authorized
    securityLogger.info({
      event: 'user_read',
      actorId: req.user.id,
      targetId: req.resource.id,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });

    res.json({
      id: req.resource.id,
      email: req.resource.email,
      role: req.resource.role,
      departmentId: req.resource.departmentId
    });
  }
);

app.put('/api/users/:id',
  adminLimiter,
  authenticate,
  authorize('user:update', loadUserResource),
  async (req, res) => {
    const { email, role } = req.body;

    // Additional validation: prevent privilege escalation
    if (role && !canAssignRole(req.user, role)) {
      securityLogger.warn({
        event: 'privilege_escalation_attempt',
        actorId: req.user.id,
        attemptedRole: role,
        timestamp: new Date().toISOString()
      });
      return res.status(403).json({ error: 'Cannot assign this role' });
    }

    await db.query(
      'UPDATE users SET email = COALESCE(?, email), role = COALESCE(?, role) WHERE id = ?',
      [email, role, req.params.id]
    );

    securityLogger.info({
      event: 'user_updated',
      actorId: req.user.id,
      targetId: req.resource.id,
      changes: { email: !!email, role: !!role },
      timestamp: new Date().toISOString()
    });

    res.json({ message: 'User updated successfully' });
  }
);

app.delete('/api/users/:id',
  adminLimiter,
  authenticate,
  authorize('user:delete', loadUserResource),
  async (req, res) => {
    // Soft delete for audit trail
    await db.query(
      'UPDATE users SET is_active = false, deleted_at = NOW(), deleted_by = ? WHERE id = ?',
      [req.user.id, req.params.id]
    );

    securityLogger.info({
      event: 'user_deleted',
      actorId: req.user.id,
      targetId: req.resource.id,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });

    res.json({ message: 'User deleted successfully' });
  }
);

// Department-scoped user listing for managers
app.get('/api/departments/:departmentId/users',
  adminLimiter,
  authenticate,
  authorize('department:manage', loadDepartmentResource),
  async (req, res) => {
    const users = await db.query(
      'SELECT id, email, role FROM users WHERE department_id = ? AND is_active = true',
      [req.params.departmentId]
    );

    res.json(users);
  }
);

// Helper function: Role hierarchy for privilege escalation prevention
const ROLE_HIERARCHY = {
  'user': 1,
  'manager': 2,
  'admin': 3,
  'superadmin': 4
};

function canAssignRole(actor, targetRole) {
  const actorLevel = ROLE_HIERARCHY[actor.role] || 0;
  const targetLevel = ROLE_HIERARCHY[targetRole] || 0;

  // Can only assign roles below your own level
  return actorLevel > targetLevel;
}

app.listen(process.env.PORT || 3000);
```

**Defense in Depth Layers**:

1. **Authentication Layer**: JWT verification with fresh database lookup
```javascript
// Never trust token claims alone - always verify against database
const user = await db.query('SELECT * FROM users WHERE id = ?', [decoded.sub]);
if (!user || !user.is_active) return res.status(401).json({ error: 'Unauthorized' });
```

2. **Function-Level Access Control**: Role-based middleware
```javascript
// Check if user's role is allowed to access this function
if (!allowedRoles.includes(req.user.role)) {
  return res.status(403).json({ error: 'Insufficient permissions' });
}
```

3. **Resource-Level Access Control**: Attribute-based permission checks
```javascript
// Check if user can access this specific resource
const isAllowed = PERMISSIONS[permission](req.user, resource);
// Managers can only access users in their own department
if (user.role === 'manager') return user.departmentId === resource.departmentId;
```

4. **Privilege Escalation Prevention**: Role hierarchy enforcement
```javascript
// Prevent users from assigning roles equal to or higher than their own
function canAssignRole(actor, targetRole) {
  return ROLE_HIERARCHY[actor.role] > ROLE_HIERARCHY[targetRole];
}
```

**Additional Protections**:
- **Rate limiting**: Prevents brute force and enumeration attacks on admin endpoints
- **Comprehensive audit logging**: All access attempts logged with actor, target, and outcome
- **Input validation**: UUID and ID format validation before database queries
- **Soft deletes**: Maintains audit trail for compliance and forensics
- **Principle of least privilege**: Users get minimum permissions needed
- **Fail-secure defaults**: Undefined permissions result in denial, not access

This is a critical security concern. Many breaches occur because developers assume hiding URLs is enough security, or they forget to add authorization checks to admin endpoints. The 2022 Optus breach exposed 9.8 million records through an unprotected API endpoint.

**VULNERABLE CODE**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import java.util.List;

@RestController
@RequestMapping("/api")
public class AdminController {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private SystemConfigRepository configRepository;

    // VULNERABLE: No authorization check - anyone can access
    @GetMapping("/admin/users")
    public List<User> getAllUsers() {
        return userRepository.findAll();
    }

    // VULNERABLE: No authorization check on sensitive operation
    @DeleteMapping("/admin/users/{id}")
    public void deleteUser(@PathVariable Long id) {
        userRepository.deleteById(id);
    }

    // VULNERABLE: Exposes system configuration to anyone
    @GetMapping("/admin/config")
    public SystemConfig getSystemConfig() {
        return configRepository.getCurrentConfig();
    }

    // VULNERABLE: Allows anyone to modify system settings
    @PostMapping("/admin/config")
    public SystemConfig updateConfig(@RequestBody SystemConfig config) {
        return configRepository.save(config);
    }
}
```

**Attack Payload**:
```bash
# Attacker discovers admin endpoint through directory brute-forcing
curl -X GET https://api.example.com/api/admin/users

# Delete arbitrary users without authentication
curl -X DELETE https://api.example.com/api/admin/users/1

# Exfiltrate system configuration
curl -X GET https://api.example.com/api/admin/config

# Modify system settings to enable attacker access
curl -X POST https://api.example.com/api/admin/config \
  -H "Content-Type: application/json" \
  -d '{"debugMode": true, "allowAnonymousAccess": true}'
```

**Why This Is Dangerous**:
- Endpoints are publicly accessible without any authentication
- No role verification - even authenticated regular users could access admin functions
- Sensitive data (user lists, system config) exposed to anyone who guesses the URL
- Destructive operations (delete, modify) can be performed by attackers
- Security through obscurity (hidden URLs) is not security

**SECURE VERSION**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.security.access.annotation.Secured;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.List;

@RestController
@RequestMapping("/api/admin")
@PreAuthorize("hasRole('ADMIN')")  // Class-level authorization
public class AdminController {

    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private SystemConfigRepository configRepository;

    // SECURE: Requires ADMIN role via class-level annotation
    @GetMapping("/users")
    public List<User> getAllUsers() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        auditLogger.info("Admin {} accessed user list", auth.getName());
        return userRepository.findAll();
    }

    // SECURE: Additional method-level check for destructive operations
    @DeleteMapping("/users/{id}")
    @PreAuthorize("hasRole('ADMIN') and hasAuthority('USER_DELETE')")
    public void deleteUser(@PathVariable Long id, Authentication authentication) {
        // Verify user exists before deletion
        User user = userRepository.findById(id)
            .orElseThrow(() -> new ResourceNotFoundException("User not found"));

        auditLogger.info("Admin {} deleted user {} (ID: {})", 
            authentication.getName(), user.getUsername(), id);

        userRepository.deleteById(id);
    }

    // SECURE: Sensitive config requires elevated privileges
    @GetMapping("/config")
    @Secured({"ROLE_ADMIN", "ROLE_SYSTEM_ADMIN"})
    public SystemConfig getSystemConfig(Authentication authentication) {
        auditLogger.info("Admin {} accessed system config", authentication.getName());
        return configRepository.getCurrentConfig();
    }

    // SECURE: Config modification requires SYSTEM_ADMIN role
    @PostMapping("/config")
    @PreAuthorize("hasRole('SYSTEM_ADMIN')")
    public SystemConfig updateConfig(@RequestBody @Valid SystemConfig config,
                                     Authentication authentication) {
        auditLogger.warn("SYSTEM_ADMIN {} modified system config", 
            authentication.getName());
        return configRepository.save(config);
    }
}
```

**Key Security Controls**:
- **@PreAuthorize at class level**: All methods in controller require ADMIN role by default
- **Method-level granular permissions**: Destructive operations require additional authorities (USER_DELETE)
- **Audit logging**: Every admin action is logged with the authenticated user's identity
- **Authentication object injection**: Spring Security provides the authenticated user context
- **Role hierarchy**: System configuration requires elevated SYSTEM_ADMIN role beyond regular ADMIN

Excellent question! This is object-level authorization (also called horizontal access control). You need to verify not just that a user has a role, but that they have rights to the specific resource they're requesting. This prevents IDOR (Insecure Direct Object Reference) attacks.

**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.security.access.prepost.PostAuthorize;
import org.springframework.security.core.Authentication;
import org.springframework.http.ResponseEntity;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.validation.Valid;
import java.util.List;

@RestController
@RequestMapping("/api/teams")
public class TeamController {

    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY");

    @Autowired
    private TeamService teamService;

    @Autowired
    private AuthorizationService authorizationService;

    @Autowired
    private RateLimiterService rateLimiter;

    /**
     * Get team members - uses custom authorization logic
     * Manager can only see their own team's members
     */
    @GetMapping("/{teamId}/members")
    @PreAuthorize("hasRole('MANAGER') or hasRole('ADMIN')")
    public ResponseEntity<List<TeamMember>> getTeamMembers(
            @PathVariable Long teamId,
            Authentication authentication) {

        String username = authentication.getName();

        // Rate limiting per user
        if (!rateLimiter.tryAcquire(username, "team-access")) {
            securityLogger.warn("Rate limit exceeded for user {} on team access", username);
            return ResponseEntity.status(429).build();
        }

        // CRITICAL: Verify user has access to this specific team
        if (!authorizationService.canAccessTeam(username, teamId)) {
            securityLogger.warn("UNAUTHORIZED_ACCESS: User {} attempted to access team {}", 
                username, teamId);
            // Return 404 instead of 403 to prevent enumeration
            return ResponseEntity.notFound().build();
        }

        auditLogger.info("User {} accessed team {} member list", username, teamId);
        List<TeamMember> members = teamService.getTeamMembers(teamId);
        return ResponseEntity.ok(members);
    }

    /**
     * Get individual employee - uses SpEL expression for authorization
     */
    @GetMapping("/{teamId}/members/{employeeId}")
    @PreAuthorize("@authorizationService.canAccessEmployee(authentication.name, #teamId, #employeeId)")
    public ResponseEntity<Employee> getEmployee(
            @PathVariable Long teamId,
            @PathVariable Long employeeId,
            Authentication authentication) {

        auditLogger.info("User {} accessed employee {} in team {}", 
            authentication.getName(), employeeId, teamId);

        Employee employee = teamService.getEmployee(teamId, employeeId);
        return ResponseEntity.ok(employee);
    }

    /**
     * Update employee - uses PostAuthorize for response filtering
     */
    @PutMapping("/{teamId}/members/{employeeId}")
    @PreAuthorize("hasRole('MANAGER') and @authorizationService.canManageEmployee(authentication.name, #teamId, #employeeId)")
    public ResponseEntity<Employee> updateEmployee(
            @PathVariable Long teamId,
            @PathVariable Long employeeId,
            @RequestBody @Valid EmployeeUpdateRequest request,
            Authentication authentication) {

        String username = authentication.getName();

        // Additional validation: prevent privilege escalation
        if (request.getRole() != null && !authorizationService.canAssignRole(username, request.getRole())) {
            securityLogger.warn("PRIVILEGE_ESCALATION_ATTEMPT: User {} tried to assign role {}", 
                username, request.getRole());
            return ResponseEntity.status(403).build();
        }

        auditLogger.info("User {} updated employee {} in team {}: {}", 
            username, employeeId, teamId, request.getChangeSummary());

        Employee updated = teamService.updateEmployee(teamId, employeeId, request);
        return ResponseEntity.ok(updated);
    }

    /**
     * Delete employee - requires additional confirmation and elevated permissions
     */
    @DeleteMapping("/{teamId}/members/{employeeId}")
    @PreAuthorize("hasRole('SENIOR_MANAGER') and @authorizationService.canDeleteEmployee(authentication.name, #teamId, #employeeId)")
    public ResponseEntity<Void> deleteEmployee(
            @PathVariable Long teamId,
            @PathVariable Long employeeId,
            @RequestHeader("X-Confirmation-Token") String confirmationToken,
            Authentication authentication) {

        String username = authentication.getName();

        // Verify confirmation token (prevents CSRF and accidental deletion)
        if (!authorizationService.verifyConfirmationToken(username, confirmationToken, "DELETE_EMPLOYEE")) {
            securityLogger.warn("Invalid confirmation token for delete by user {}", username);
            return ResponseEntity.badRequest().build();
        }

        auditLogger.warn("DESTRUCTIVE_ACTION: User {} deleted employee {} from team {}", 
            username, employeeId, teamId);

        teamService.deleteEmployee(teamId, employeeId);
        return ResponseEntity.noContent().build();
    }
}
```

```java
import org.springframework.stereotype.Service;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.cache.annotation.Cacheable;
import java.util.Set;

@Service
public class AuthorizationService {

    @Autowired
    private TeamRepository teamRepository;

    @Autowired
    private EmployeeRepository employeeRepository;

    @Autowired
    private RoleHierarchyService roleHierarchy;

    /**
     * Check if user can access a specific team
     */
    @Cacheable(value = "teamAccess", key = "#username + '-' + #teamId")
    public boolean canAccessTeam(String username, Long teamId) {
        // Admin can access all teams
        if (roleHierarchy.hasRole(username, "ADMIN")) {
            return true;
        }

        // Get teams user manages directly or indirectly
        Set<Long> accessibleTeams = teamRepository.findAccessibleTeamIds(username);
        return accessibleTeams.contains(teamId);
    }

    /**
     * Check if user can access specific employee
     */
    public boolean canAccessEmployee(String username, Long teamId, Long employeeId) {
        // First verify team access
        if (!canAccessTeam(username, teamId)) {
            return false;
        }

        // Then verify employee belongs to that team
        return employeeRepository.existsByIdAndTeamId(employeeId, teamId);
    }

    /**
     * Check if user can manage (modify) employee
     */
    public boolean canManageEmployee(String username, Long teamId, Long employeeId) {
        // Must have access first
        if (!canAccessEmployee(username, teamId, employeeId)) {
            return false;
        }

        // Cannot modify yourself (prevent self-privilege escalation)
        Employee employee = employeeRepository.findById(employeeId).orElse(null);
        if (employee != null && employee.getUsername().equals(username)) {
            return false;
        }

        // Check if user is direct manager
        return teamRepository.isDirectManager(username, teamId);
    }

    /**
     * Check if user can assign a specific role
     */
    public boolean canAssignRole(String username, String targetRole) {
        // User can only assign roles below their own level
        int userLevel = roleHierarchy.getRoleLevel(username);
        int targetLevel = roleHierarchy.getRoleLevelByName(targetRole);
        return userLevel > targetLevel;
    }

    /**
     * Check if user can delete employee (elevated permission)
     */
    public boolean canDeleteEmployee(String username, Long teamId, Long employeeId) {
        return canManageEmployee(username, teamId, employeeId) 
            && roleHierarchy.hasRole(username, "SENIOR_MANAGER");
    }

    /**
     * Verify confirmation token for destructive operations
     */
    public boolean verifyConfirmationToken(String username, String token, String operation) {
        // Token should be time-limited and operation-specific
        return tokenService.verify(username, token, operation);
    }
}
