// RequireRole middleware enforces function-level access control
func RequireRole(allowedRoles ...string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			user, ok := r.Context().Value(userContextKey).(*AuthenticatedUser)
			if !ok || user == nil {
				log.Printf("SECURITY: Unauthenticated access attempt to %s from %s",
					r.URL.Path, r.RemoteAddr)
				http.Error(w, "Unauthorized", http.StatusUnauthorized)
				return
			}

			authorized := false
			for _, role := range allowedRoles {
				if strings.EqualFold(user.Role, role) {
					authorized = true
					break
				}
			}

			if !authorized {
				log.Printf("SECURITY: Unauthorized access attempt by user %d (role: %s) to %s",
					user.ID, user.Role, r.URL.Path)
				http.Error(w, "Forbidden", http.StatusForbidden)
				return
			}

			log.Printf("AUDIT: User %d (role: %s) accessed %s", user.ID, user.Role, r.URL.Path)
			next.ServeHTTP(w, r)
		})
	}
}

// SECURE: Protected by authorization middleware
func AdminGetAllUsers(w http.ResponseWriter, r *http.Request) {
	rows, err := db.Query("SELECT id, username, email, role FROM users")
	if err != nil {
