**Key Security Controls**:
- **Role-based middleware**: Every admin endpoint is protected by `RequireRole()` middleware that verifies the user's role before allowing access
- **Context-based user extraction**: User identity is extracted from a secure context (set by authentication middleware) rather than trusting client input
- **Security logging**: All access attempts (successful and failed) are logged with user ID, role, and endpoint for audit trails
- **Fail-secure design**: Missing or invalid authentication results in denial by default

Excellent question! For granular control, you need Permission-Based Access Control (PBAC) or Attribute-Based Access Control (ABAC) rather than simple role checks. This is critical for enterprise applications where different admin roles have varying capabilities.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

var db *sql.DB

type contextKey string

const userContextKey contextKey = "authenticated_user"

// Permission constants - use typed constants for safety
type Permission string

const (
	PermUserRead    Permission = "users:read"
	PermUserWrite   Permission = "users:write"
	PermUserDelete  Permission = "users:delete"
	PermAuditRead   Permission = "audit:read"
	PermSystemAdmin Permission = "system:admin"
)

type AuthenticatedUser struct {
	ID          int
	Username    string
	Role        string
	Permissions map[Permission]bool
	SessionID   string
	IPAddress   string
}

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	Role     string `json:"role"`
}

// PermissionCache with TTL for performance
type PermissionCache struct {
	cache map[int]cachedPermissions
	mu    sync.RWMutex
}

type cachedPermissions struct {
	perms   map[Permission]bool
	expires time.Time
}

var permCache = &PermissionCache{
	cache: make(map[int]cachedPermissions),
}

const permCacheTTL = 5 * time.Minute

// GetUserPermissions loads permissions from database with caching
func GetUserPermissions(userID int) (map[Permission]bool, error) {
	// Check cache first
	permCache.mu.RLock()
	if cached, ok := permCache.cache[userID]; ok && time.Now().Before(cached.expires) {
		permCache.mu.RUnlock()
		return cached.perms, nil
	}
	permCache.mu.RUnlock()

	// Load from database
	query := `
		SELECT p.permission_name 
		FROM permissions p
		JOIN role_permissions rp ON p.id = rp.permission_id
		JOIN user_roles ur ON rp.role_id = ur.role_id
		WHERE ur.user_id = $1
		UNION
		SELECT p.permission_name
		FROM permissions p
		JOIN user_permissions up ON p.id = up.permission_id
		WHERE up.user_id = $1`

	rows, err := db.Query(query, userID)
	if err != nil {
		return nil, fmt.Errorf("failed to load permissions: %w", err)
	}
	defer rows.Close()

	perms := make(map[Permission]bool)
	for rows.Next() {
		var permName string
		if err := rows.Scan(&permName); err != nil {
			continue
		}
		perms[Permission(permName)] = true
	}

	// Update cache
	permCache.mu.Lock()
	permCache.cache[userID] = cachedPermissions{
		perms:   perms,
		expires: time.Now().Add(permCacheTTL),
	}
	permCache.mu.Unlock()

	return perms, nil
}

// RequirePermission middleware enforces granular permission checks
func RequirePermission(required ...Permission) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			user, ok := r.Context().Value(userContextKey).(*AuthenticatedUser)
			if !ok || user == nil {
				logSecurityEvent("AUTH_FAILURE", 0, r.URL.Path, r.RemoteAddr,
					"No authenticated user in context")
				http.Error(w, `{"error": "unauthorized"}`, http.StatusUnauthorized)
				return
			}

			// Check each required permission
			missingPerms := []Permission{}
			for _, perm := range required {
				if !user.Permissions[perm] {
					missingPerms = append(missingPerms, perm)
				}
			}

			if len(missingPerms) > 0 {
				logSecurityEvent("AUTHZ_FAILURE", user.ID, r.URL.Path, r.RemoteAddr,
					fmt.Sprintf("Missing permissions: %v", missingPerms))

				// Rate limit failed authorization attempts
				if isRateLimited(user.ID, "authz_failure") {
					logSecurityEvent("RATE_LIMIT", user.ID, r.URL.Path, r.RemoteAddr,
						"Too many authorization failures")
					http.Error(w, `{"error": "too many requests"}`, http.StatusTooManyRequests)
					return
				}

				http.Error(w, `{"error": "forbidden"}`, http.StatusForbidden)
				return
			}

			// Log successful authorization for audit
			logAuditEvent(user.ID, r.Method, r.URL.Path, "AUTHORIZED")
			next.ServeHTTP(w, r)
		})
	}
}

// AuthenticationMiddleware validates JWT and loads user context
func AuthenticationMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		token := extractBearerToken(r)
		if token == "" {
			http.Error(w, `{"error": "missing token"}`, http.StatusUnauthorized)
			return
		}

		// Validate JWT and extract claims (implementation depends on your JWT library)
		userID, sessionID, err := validateJWT(token)
		if err != nil {
			logSecurityEvent("TOKEN_INVALID", 0, r.URL.Path, r.RemoteAddr, err.Error())
			http.Error(w, `{"error": "invalid token"}`, http.StatusUnauthorized)
			return
		}

		// Load user permissions
		perms, err := GetUserPermissions(userID)
		if err != nil {
			log.Printf("ERROR: Failed to load permissions for user %d: %v", userID, err)
			http.Error(w, `{"error": "internal error"}`, http.StatusInternalServerError)
			return
		}

		user := &AuthenticatedUser{
			ID:          userID,
			Permissions: perms,
			SessionID:   sessionID,
			IPAddress:   r.RemoteAddr,
		}

		ctx := context.WithValue(r.Context(), userContextKey, user)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// AdminGetAllUsers - requires users:read permission
func AdminGetAllUsers(w http.ResponseWriter, r *http.Request) {
	user := r.Context().Value(userContextKey).(*AuthenticatedUser)

	rows, err := db.Query("SELECT id, username, email, role FROM users")
	if err != nil {
		log.Printf("ERROR: Database query failed for user %d: %v", user.ID, err)
		http.Error(w, `{"error": "internal error"}`, http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	var users []User
	for rows.Next() {
		var u User
		if err := rows.Scan(&u.ID, &u.Username, &u.Email, &u.Role); err != nil {
			log.Printf("ERROR: Row scan failed: %v", err)
			continue
		}
		users = append(users, u)
	}

	logAuditEvent(user.ID, "GET", "/api/admin/users",
		fmt.Sprintf("Retrieved %d users", len(users)))

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(users)
}

// AdminDeleteUser - requires users:delete permission
func AdminDeleteUser(w http.ResponseWriter, r *http.Request) {
	user := r.Context().Value(userContextKey).(*AuthenticatedUser)
	vars := mux.Vars(r)
	targetID := vars["id"]

	// Prevent self-deletion
	if fmt.Sprintf("%d", user.ID) == targetID {
		logSecurityEvent("SELF_DELETE_ATTEMPT", user.ID, r.URL.Path, r.RemoteAddr, "")
		http.Error(w, `{"error": "cannot delete self"}`, http.StatusBadRequest)
		return
	}

	// Check if target exists and get their role
	var targetRole string
	err := db.QueryRow("SELECT role FROM users WHERE id = $1", targetID).Scan(&targetRole)
	if err == sql.ErrNoRows {
		http.Error(w, `{"error": "user not found"}`, http.StatusNotFound)
		return
	}
	if err != nil {
		log.Printf("ERROR: Database query failed: %v", err)
		http.Error(w, `{"error": "internal error"}`, http.StatusInternalServerError)
		return
	}

	// Prevent deleting superadmins unless you're a superadmin
	if targetRole == "superadmin" && !user.Permissions[PermSystemAdmin] {
		logSecurityEvent("PRIVILEGE_ESCALATION_ATTEMPT", user.ID, r.URL.Path,
			r.RemoteAddr, fmt.Sprintf("Attempted to delete superadmin %s", targetID))
		http.Error(w, `{"error": "forbidden"}`, http.StatusForbidden)
		return
	}

	// Perform deletion
	_, err = db.Exec("DELETE FROM users WHERE id = $1", targetID)
	if err != nil {
		log.Printf("ERROR: Delete failed: %v", err)
		http.Error(w, `{"error": "delete failed"}`, http.StatusInternalServerError)
		return
	}

	logAuditEvent(user.ID, "DELETE", r.URL.Path,
		fmt.Sprintf("Deleted user %s (role: %s)", targetID, targetRole))

	w.WriteHeader(http.StatusNoContent)
}

// Security event logging
func logSecurityEvent(eventType string, userID int, path, ip, details string) {
	log.Printf("SECURITY [%s] user=%d path=%s ip=%s details=%s",
		eventType, userID, path, ip, details)

	// In production, also write to security monitoring system
	_, _ = db.Exec(`
		INSERT INTO security_events (event_type, user_id, path, ip_address, details, created_at)
		VALUES ($1, $2, $3, $4, $5, NOW())`,
		eventType, userID, path, ip, details)
}

// Audit event logging
func logAuditEvent(userID int, method, path, details string) {
	log.Printf("AUDIT user=%d method=%s path=%s details=%s",
		userID, method, path, details)

	_, _ = db.Exec(`
		INSERT INTO audit_log (user_id, method, path, details, created_at)
		VALUES ($1, $2, $3, $4, NOW())`,
		userID, method, path, details)
}

// Rate limiting stub (implement with Redis in production)
func isRateLimited(userID int, action string) bool {
	// Implement with Redis: INCR authz_fail:{userID}, EXPIRE 300
	return false
}

func extractBearerToken(r *http.Request) string {
	auth := r.Header.Get("Authorization")
	if len(auth) > 7 && auth[:7] == "Bearer " {
		return auth[7:]
	}
	return ""
