		RequirePermission(PermUserRead)(http.HandlerFunc(AdminGetAllUsers))).Methods("GET")

	// Destructive operations require specific permission
	adminRouter.Handle("/users/{id}",
		RequirePermission(PermUserDelete)(http.HandlerFunc(AdminDeleteUser))).Methods("DELETE")

	// Start server with security headers
	server := &http.Server{
		Addr:         ":8080",
