        $this->pdo = $pdo;
    }

    // Anyone can call this if they know the URL!
    public function getAllUsers() {
        $stmt = $this->pdo->query("SELECT * FROM users");
        return json_encode($stmt->fetchAll(PDO::FETCH_ASSOC));
    }

    // No check if user is admin before deleting
    public function deleteUser($userId) {
        $stmt = $this->pdo->prepare("DELETE FROM users WHERE id = ?");
        $stmt->execute([$userId]);
        return json_encode(['status' => 'success']);
    }

    // Privilege escalation: anyone can make themselves admin
    public function promoteToAdmin($userId) {
        $stmt = $this->pdo->prepare("UPDATE users SET role = 'admin' WHERE id = ?");
        $stmt->execute([$userId]);
        return json_encode(['status' => 'promoted']);
    }
}

