});
```

- **Security Headers**: Ensure API responses include security headers
- **Input Validation**: Validate all user IDs are positive integers before processing

Excellent question! Real-world applications need hierarchical role-based access control (RBAC) with granular permissions. Here's a production-ready pattern with permission inheritance and fine-grained access control.

**PRODUCTION PATTERN**:

```python
from flask import Flask, request, jsonify, g, abort
from functools import wraps
from enum import Enum, auto
from typing import Set, List, Optional, Callable
import sqlite3
import jwt
import logging
from datetime import datetime, timedelta
import hashlib
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY', 'dev-key-change-in-prod')
app.config['ENV'] = os.environ.get('FLASK_ENV', 'development')

# Configure structured logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger('authorization')


class Permission(Enum):
    """Fine-grained permissions for RBAC"""
    # User management
    USER_READ = auto()
    USER_CREATE = auto()
    USER_UPDATE = auto()
    USER_DELETE = auto()

    # Content management
    CONTENT_READ = auto()
    CONTENT_CREATE = auto()
    CONTENT_UPDATE = auto()
    CONTENT_DELETE = auto()
    CONTENT_MODERATE = auto()

    # System administration
    SYSTEM_CONFIG = auto()
    AUDIT_LOG_READ = auto()
    ROLE_MANAGE = auto()


class Role:
    """Role with hierarchical permissions"""

    # Define role hierarchy with explicit permissions
    ROLE_PERMISSIONS = {
        'user': {
            Permission.USER_READ,
            Permission.CONTENT_READ,
            Permission.CONTENT_CREATE,
        },
        'support': {
            Permission.USER_READ,
            Permission.USER_UPDATE,  # Can update user profiles
            Permission.CONTENT_READ,
            Permission.CONTENT_CREATE,
            Permission.CONTENT_UPDATE,
        },
        'moderator': {
            Permission.USER_READ,
            Permission.USER_UPDATE,
            Permission.CONTENT_READ,
            Permission.CONTENT_CREATE,
            Permission.CONTENT_UPDATE,
            Permission.CONTENT_DELETE,
            Permission.CONTENT_MODERATE,
        },
        'admin': {
            Permission.USER_READ,
            Permission.USER_CREATE,
            Permission.USER_UPDATE,
            Permission.USER_DELETE,
            Permission.CONTENT_READ,
            Permission.CONTENT_CREATE,
            Permission.CONTENT_UPDATE,
            Permission.CONTENT_DELETE,
            Permission.CONTENT_MODERATE,
            Permission.AUDIT_LOG_READ,
        },
        'superadmin': set(Permission),  # All permissions
    }

    # Role hierarchy for >= comparisons
    ROLE_HIERARCHY = {
        'user': 1,
        'support': 2,
        'moderator': 3,
        'admin': 4,
        'superadmin': 5,
    }

    @classmethod
    def get_permissions(cls, role_name: str) -> Set[Permission]:
        """Get all permissions for a role"""
        return cls.ROLE_PERMISSIONS.get(role_name, set())

    @classmethod
    def has_permission(cls, role_name: str, permission: Permission) -> bool:
        """Check if role has specific permission"""
        return permission in cls.get_permissions(role_name)

    @classmethod
    def get_hierarchy_level(cls, role_name: str) -> int:
        """Get numeric hierarchy level for role comparison"""
        return cls.ROLE_HIERARCHY.get(role_name, 0)


class AuditLogger:
    """Centralized audit logging for security events"""

    @staticmethod
    def log_access_attempt(
        user_id: Optional[int],
        action: str,
        resource: str,
        success: bool,
        ip_address: str,
        details: Optional[str] = None
    ):
        """Log access attempt for audit trail"""
        event = {
            'timestamp': datetime.utcnow().isoformat(),
            'user_id': user_id,
            'action': action,
            'resource': resource,
            'success': success,
            'ip_address': ip_address,
            'details': details,
            'request_id': request.headers.get('X-Request-ID', 'unknown')
        }

        if success:
            logger.info(f"ACCESS_GRANTED: {event}")
        else:
            logger.warning(f"ACCESS_DENIED: {event}")

        # In production, also write to database or SIEM
        # AuditLogger._persist_to_db(event)


def get_db_connection():
    """Get database connection with row factory"""
    conn = sqlite3.connect('users.db')
    conn.row_factory = sqlite3.Row
    return conn


def require_auth(f: Callable) -> Callable:
    """Decorator requiring valid JWT authentication"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')

        if not auth_header.startswith('Bearer '):
            AuditLogger.log_access_attempt(
                None, f.__name__, request.path, False,
                request.remote_addr, "Missing or invalid auth header"
            )
            abort(401, description="Authentication required")

        token = auth_header[7:]  # Remove 'Bearer ' prefix

        try:
            payload = jwt.decode(
                token,
                app.config['SECRET_KEY'],
                algorithms=['HS256'],
                options={'require': ['exp', 'iat', 'sub', 'role']}
            )

            # Validate token hasn't been revoked (check against blacklist)
            if is_token_revoked(payload.get('jti')):
                raise jwt.InvalidTokenError("Token has been revoked")

            g.current_user = {
                'user_id': payload['sub'],
                'role': payload['role'],
                'permissions': list(Role.get_permissions(payload['role'])),
                'token_id': payload.get('jti')
            }

        except jwt.ExpiredSignatureError:
            AuditLogger.log_access_attempt(
                None, f.__name__, request.path, False,
                request.remote_addr, "Expired token"
            )
            abort(401, description="Token has expired")
        except jwt.InvalidTokenError as e:
            AuditLogger.log_access_attempt(
                None, f.__name__, request.path, False,
                request.remote_addr, f"Invalid token: {str(e)}"
            )
            abort(401, description="Invalid authentication token")

        return f(*args, **kwargs)
    return decorated_function


def is_token_revoked(token_id: Optional[str]) -> bool:
    """Check if token has been revoked (logout, password change, etc.)"""
    if not token_id:
        return False
    # In production, check Redis or database for revoked tokens
    # return redis_client.sismember('revoked_tokens', token_id)
    return False


def require_permission(*required_permissions: Permission):
    """Decorator requiring specific permissions (ANY of the listed)"""
    def decorator(f: Callable) -> Callable:
        @wraps(f)
        def decorated_function(*args, **kwargs):
            user_role = g.current_user.get('role', '')
            user_id = g.current_user.get('user_id')

            # Check if user has ANY of the required permissions
            has_access = any(
                Role.has_permission(user_role, perm)
                for perm in required_permissions
            )

            if not has_access:
                AuditLogger.log_access_attempt(
                    user_id, f.__name__, request.path, False,
                    request.remote_addr,
                    f"Missing permissions: {[p.name for p in required_permissions]}"
                )
                abort(403, description="Insufficient permissions")

            AuditLogger.log_access_attempt(
                user_id, f.__name__, request.path, True,
                request.remote_addr, f"Role: {user_role}"
            )

            return f(*args, **kwargs)
        return decorated_function
    return decorator


def require_all_permissions(*required_permissions: Permission):
    """Decorator requiring ALL specified permissions"""
    def decorator(f: Callable) -> Callable:
        @wraps(f)
        def decorated_function(*args, **kwargs):
            user_role = g.current_user.get('role', '')
            user_id = g.current_user.get('user_id')

            # Check if user has ALL required permissions
            missing = [
                perm for perm in required_permissions
                if not Role.has_permission(user_role, perm)
            ]

            if missing:
                AuditLogger.log_access_attempt(
                    user_id, f.__name__, request.path, False,
                    request.remote_addr,
                    f"Missing permissions: {[p.name for p in missing]}"
                )
                abort(403, description="Insufficient permissions")

            return f(*args, **kwargs)
        return decorated_function
    return decorator


def require_minimum_role(minimum_role: str):
    """Decorator requiring minimum role level in hierarchy"""
    def decorator(f: Callable) -> Callable:
        @wraps(f)
        def decorated_function(*args, **kwargs):
            user_role = g.current_user.get('role', '')
            user_id = g.current_user.get('user_id')

            user_level = Role.get_hierarchy_level(user_role)
            required_level = Role.get_hierarchy_level(minimum_role)

            if user_level < required_level:
                AuditLogger.log_access_attempt(
                    user_id, f.__name__, request.path, False,
                    request.remote_addr,
                    f"Role '{user_role}' below minimum '{minimum_role}'"
                )
                abort(403, description="Insufficient role level")

            return f(*args, **kwargs)
        return decorated_function
    return decorator


