@app.route('/api/users/<int:user_id>', methods=['DELETE'])
@require_auth
@require_permission(Permission.USER_DELETE)
def delete_user(user_id: int):
    """Delete user - requires USER_DELETE permission (admin only)"""
    current_user_id = g.current_user.get('user_id')

    # Prevent self-deletion
    if current_user_id == user_id:
        abort(400, description="Cannot delete your own account")

    conn = get_db_connection()
    cursor = conn.cursor()

    # Check target user exists and get their role
    cursor.execute('SELECT id, username, role FROM users WHERE id = ?', (user_id,))
    target_user = cursor.fetchone()

    if not target_user:
        conn.close()
        abort(404, description="User not found")

    # Prevent deleting users with higher/equal privilege
    current_level = Role.get_hierarchy_level(g.current_user.get('role'))
    target_level = Role.get_hierarchy_level(target_user['role'])

    if target_level >= current_level:
        AuditLogger.log_access_attempt(
            current_user_id, 'delete_user', f'/api/users/{user_id}', False,
            request.remote_addr,
            f"Attempted to delete higher/equal role: {target_user['role']}"
        )
        abort(403, description="Cannot delete user with equal or higher privileges")

    # Perform deletion
    cursor.execute('DELETE FROM users WHERE id = ?', (user_id,))
    conn.commit()
    conn.close()

    logger.info(
        f"USER_DELETED: {target_user['username']} (id={user_id}) "
        f"by user_id={current_user_id} from {request.remote_addr}"
    )

    return jsonify({'message': f"User {target_user['username']} deleted"})


