    @GetMapping("/users")
    @PreAuthorize("hasAuthority('USER_READ')")
    public List<UserDTO> getAllUsers(@AuthenticationPrincipal UserDetails principal) {
        auditLog.info("Admin {} accessed user list", principal.getUsername());
        // Return DTO without sensitive fields
        return userRepository.findAll().stream()
            .map(UserDTO::fromEntity)
            .toList();
    }

    // SECURE: Requires elevated permission + audit logging
    @DeleteMapping("/users/{id}")
    @PreAuthorize("hasAuthority('USER_DELETE')")
    public void deleteUser(@PathVariable Long id, 
                          @AuthenticationPrincipal UserDetails principal) {
        auditLog.warn("Admin {} deleting user ID: {}", principal.getUsername(), id);

        // Prevent self-deletion
        User currentUser = userRepository.findByUsername(principal.getUsername());
        if (currentUser.getId().equals(id)) {
            throw new ForbiddenException("Cannot delete your own account");
        }

        userRepository.deleteById(id);
    }

    // SECURE: Super admin only for config changes
    @PostMapping("/config")
    @PreAuthorize("hasRole('SUPER_ADMIN')")
    public SystemConfig updateConfig(@RequestBody @Valid SystemConfig config,
                                    @AuthenticationPrincipal UserDetails principal) {
        auditLog.warn("CRITICAL: Admin {} modifying system config", 
                     principal.getUsername());
        return configRepository.save(config);
    }
}
```

**Key Security Controls**:
- `@PreAuthorize` at class level ensures all methods require ADMIN role by default
- Method-level `@PreAuthorize` adds granular permission checks (USER_READ, USER_DELETE)
- `@AuthenticationPrincipal` provides verified user identity for audit logging
- DTOs prevent accidental exposure of sensitive entity fields
- Comprehensive audit logging for all admin operations

Excellent question! Resource-based authorization (also called object-level authorization) is essential when access depends on the relationship between the user and the specific resource. This is where IDOR (Insecure Direct Object Reference) vulnerabilities commonly occur.

**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.stereotype.Component;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.Optional;

// Custom Security Expression for resource-based authorization
@Component("documentSecurity")
public class DocumentSecurityEvaluator {

    @Autowired
    private DocumentRepository documentRepository;

    @Autowired
    private TeamMembershipRepository teamMembershipRepository;

    private static final Logger auditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    public boolean canRead(Long documentId, UserDetails principal) {
        Optional<Document> doc = documentRepository.findById(documentId);
        if (doc.isEmpty()) {
            return false; // Fail closed
        }

        Document document = doc.get();
        User user = getUserFromPrincipal(principal);

        // Check multiple authorization paths
        boolean authorized = 
            document.getOwnerId().equals(user.getId()) ||              // Owner
            document.isPublic() ||                                      // Public doc
            hasTeamAccess(user, document) ||                           // Team member
            user.hasRole("ADMIN");                                     // Admin override

        // Audit all access attempts
        auditLog.info("Document access check: user={}, doc={}, authorized={}",
                     user.getId(), documentId, authorized);

        return authorized;
    }

    public boolean canWrite(Long documentId, UserDetails principal) {
        Optional<Document> doc = documentRepository.findById(documentId);
        if (doc.isEmpty()) {
            return false;
        }

        Document document = doc.get();
        User user = getUserFromPrincipal(principal);

        // Write requires owner or explicit write permission
        boolean authorized = 
            document.getOwnerId().equals(user.getId()) ||
            hasTeamWriteAccess(user, document) ||
            user.hasRole("ADMIN");

        auditLog.info("Document write check: user={}, doc={}, authorized={}",
                     user.getId(), documentId, authorized);

        return authorized;
    }

    public boolean canDelete(Long documentId, UserDetails principal) {
        Optional<Document> doc = documentRepository.findById(documentId);
        if (doc.isEmpty()) {
            return false;
        }

        Document document = doc.get();
        User user = getUserFromPrincipal(principal);

        // Delete is owner-only (no team delegation)
        boolean authorized = 
            document.getOwnerId().equals(user.getId()) ||
            user.hasRole("ADMIN");

        auditLog.warn("Document DELETE check: user={}, doc={}, authorized={}",
                     user.getId(), documentId, authorized);

        return authorized;
    }

    private boolean hasTeamAccess(User user, Document document) {
        return teamMembershipRepository
            .existsByUserIdAndTeamId(user.getId(), document.getTeamId());
    }

    private boolean hasTeamWriteAccess(User user, Document document) {
        return teamMembershipRepository
            .existsByUserIdAndTeamIdAndRole(user.getId(), document.getTeamId(), "EDITOR");
    }

    private User getUserFromPrincipal(UserDetails principal) {
        return userRepository.findByUsername(principal.getUsername())
            .orElseThrow(() -> new SecurityException("Invalid principal"));
    }
}

// Controller using resource-based authorization
@RestController
@RequestMapping("/api/documents")
public class DocumentController {

    private static final Logger auditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    @Autowired
    private DocumentService documentService;

    // Resource-based read authorization
    @GetMapping("/{id}")
    @PreAuthorize("@documentSecurity.canRead(#id, principal)")
    public DocumentDTO getDocument(@PathVariable Long id,
                                   @AuthenticationPrincipal UserDetails principal) {
        auditLog.info("Document read: id={}, user={}", id, principal.getUsername());
        return documentService.getDocument(id);
    }

    // Resource-based write authorization
    @PutMapping("/{id}")
    @PreAuthorize("@documentSecurity.canWrite(#id, principal)")
    public DocumentDTO updateDocument(@PathVariable Long id,
                                     @RequestBody @Valid DocumentUpdateRequest request,
                                     @AuthenticationPrincipal UserDetails principal) {
        auditLog.info("Document update: id={}, user={}", id, principal.getUsername());
        return documentService.updateDocument(id, request);
    }

    // Resource-based delete with extra confirmation
    @DeleteMapping("/{id}")
    @PreAuthorize("@documentSecurity.canDelete(#id, principal)")
    public void deleteDocument(@PathVariable Long id,
                              @RequestHeader("X-Confirm-Delete") String confirmation,
                              @AuthenticationPrincipal UserDetails principal) {
        if (!"CONFIRM".equals(confirmation)) {
            throw new BadRequestException("Delete confirmation required");
        }

        auditLog.warn("Document DELETE: id={}, user={}", id, principal.getUsername());
        documentService.deleteDocument(id);
    }

    // List only documents user can access
    @GetMapping
    public List<DocumentDTO> listDocuments(@AuthenticationPrincipal UserDetails principal,
                                          @RequestParam(defaultValue = "0") int page,
                                          @RequestParam(defaultValue = "20") int size) {
        // Query filters by user's accessible documents
        User user = userService.getCurrentUser(principal);
        return documentService.findAccessibleDocuments(user, page, Math.min(size, 100));
    }
}
