// Custom permission evaluator for complex scenarios
@Component
public class CustomPermissionEvaluator implements PermissionEvaluator {

    @Autowired
    private Map<String, ResourceSecurityEvaluator> evaluators;

    @Override
    public boolean hasPermission(Authentication auth, Object target, Object permission) {
        if (target == null) {
            return false; // Fail closed
        }

        String resourceType = target.getClass().getSimpleName().toLowerCase();
        ResourceSecurityEvaluator evaluator = evaluators.get(resourceType);

        if (evaluator == null) {
            // Unknown resource type - deny by default
            return false;
        }

        return evaluator.hasPermission(auth, target, permission.toString());
    }
}
